import{z as t}from"zod";export const GenreSchema=t.string().min(1),PlatformSchema=t.enum(["tomato","feilu","qidian","other"]),BookStatusSchema=t.enum(["incubating","outlining","active","paused","completed","dropped"]),FanficModeSchema=t.enum(["canon","au","ooc","cp"]),BookConfigSchema=t.object({id:t.string().min(1),title:t.string().min(1),platform:PlatformSchema.default("other"),genre:GenreSchema,status:BookStatusSchema.default("incubating"),targetChapters:t.number().int().min(1).default(200),chapterWordCount:t.number().int().min(1e3).default(2e3),language:t.enum(["zh","en"]).default("zh"),createdAt:t.string().datetime(),updatedAt:t.string().datetime(),parentBookId:t.string().optional(),fanficMode:FanficModeSchema.optional(),writing:t.object({reviewMode:t.enum(["auto","manual"]).default("auto"),reviewRetries:t.number().int().min(0).max(10).default(1)}).default({reviewMode:"auto",reviewRetries:1})}),BookMetaSchema=t.object({config:BookConfigSchema,chapterCount:t.number().int().min(0).default(0),totalWords:t.number().int().min(0).default(0),lastChapterAt:t.string().datetime().optional(),coverPath:t.string().optional(),tags:t.array(t.string()).default([])});
